<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <style>
        :root {
            --color-primary: #007bff;
            --color-background: #f4f6f9;
            --color-card-bg: #ffffff;
            --color-border: #ddd;
            --color-text: #333;
            --color-shadow: rgba(0, 0, 0, 0.1);
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--color-background);
            padding: 20px;
            margin: 0;
            display: flex;
            flex-direction: column;
            gap: 20px;
        }

        /* Card Input Area */
        #card-input-area {
            background: var(--color-card-bg);
            padding: 15px;
            border-radius: 8px;
            box-shadow: 0 2px 4px var(--color-shadow);
            display: flex;
            gap: 10px;
            align-items: center;
        }

        #new-card {
            flex-grow: 1;
            padding: 10px;
            border: 1px solid var(--color-border);
            border-radius: 6px;
            font-size: 16px;
        }

        #add-card {
            background-color: var(--color-primary);
            color: white;
            padding: 10px 20px;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-size: 16px;
            transition: background-color 0.2s;
        }

        #add-card:hover {
            background-color: #0056b3;
        }

        /* Board Layout */
        #kanban-board {
            display: flex;
            gap: 20px;
            min-height: 70vh; /* Ensure columns are visible even if empty */
        }

        .column {
            flex: 1;
            background-color: #e9ecef;
            border-radius: 8px;
            padding: 15px;
            box-shadow: inset 0 0 10px rgba(0, 0, 0, 0.05);
            display: flex;
            flex-direction: column;
        }

        .column-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            padding-bottom: 10px;
            margin-bottom: 15px;
            border-bottom: 2px solid var(--color-primary);
        }

        .column-header h2 {
            margin: 0;
            font-size: 1.4em;
            color: var(--color-text);
        }

        .count {
            background-color: var(--color-primary);
            color: white;
            padding: 5px 10px;
            border-radius: 15px;
            font-weight: bold;
            font-size: 0.9em;
        }

        /* Card Container */
        .card-container {
            flex-grow: 1;
            display: flex;
            flex-direction: column;
            gap: 10px;
            padding-bottom: 10px; /* Space for the last card/drag target */
            min-height: 50px; /* Ensures drop zone is visible */
        }

        /* Card Styling */
        .card {
            background-color: var(--color-card-bg);
            padding: 15px;
            border-radius: 6px;
            box-shadow: 0 2px 4px var(--color-shadow);
            cursor: grab;
            display: flex;
            justify-content: space-between;
            align-items: flex-start;
            transition: transform 0.1s, box-shadow 0.1s;
        }

        .card:hover {
            box-shadow: 0 4px 8px rgba(0, 0, 0, 0.15);
        }

        /* Dragging feedback */
        .dragging {
            opacity: 0.4;
            transform: scale(0.98);
            box-shadow: 0 10px 20px rgba(0, 0, 0, 0.2);
        }

        /* Drop target feedback */
        .drag-over {
            border-top: 3px solid var(--color-primary);
            margin-top: -3px; /* Overlap border slightly for visual effect */
        }


        /* Delete Button */
        .card-del {
            background: none;
            border: none;
            color: #dc3545;
            cursor: pointer;
            font-size: 1.2em;
            padding = 0 5px;
            margin-left: 10px;
            opacity: 0.7;
            transition: opacity 0.2s, transform 0.2s;
        }

        .card-del:hover {
            opacity: 1;
            transform: scale(1.1);
        }
    </style>
</head>
<body>

    <div id="card-input-area">
        <input type="text" id="new-card" placeholder="Enter new card title...">
        <button id="add-card">Add Card</button>
    </div>

    <div id="kanban-board">
        <!-- To Do Column -->
        <div class="column" id="col-todo" data-status="todo">
            <div class="column-header">
                <h2>To Do</h2>
                <span class="count" data-count="0">0</span>
            </div>
            <div class="card-container" data-status="todo"></div>
        </div>

        <!-- Doing Column -->
        <div class="column" id="col-doing" data-status="doing">
            <div class="column-header">
                <h2>Doing</h2>
                <span class="count" data-count="0">0</span>
            </div>
            <div class="card-container" data-status="doing"></div>
        </div>

        <!-- Done Column -->
        <div class="column" id="col-done" data-status="done">
            <div class="column-header">
                <h2>Done</h2>
                <span class="count" data-count="0">0</span>
            </div>
            <div class="card-container" data-status="done"></div>
        </div>
    </div>

    <script>
        const STORAGE_KEY = 'kanbanBoardState';
        const cardInput = document.getElementById('new-card');
        const addCardButton = document.getElementById('add-card');
        const columns = {
            todo: document.querySelector('#col-todo .card-container'),
            doing: document.querySelector('#col-doing .card-container'),
            done: document.querySelector('#col-done .card-container')
        };
        const countSpans = {
            todo: document.querySelector('#col-todo .count'),
            doing: document.querySelector('#col-doing .count'),
            done: document.querySelector('#col-done .count')
        };

        let draggedCardElement = null;

        // --- State Management ---

        /**
         * Saves the current state of all cards to localStorage.
         */
        function saveBoardState() {
            const boardState = [];
            document.querySelectorAll('.card').forEach(cardEl => {
                const status = cardEl.closest('.column-header').parentElement.id.replace('col-', '');
                boardState.push({
                    title: cardEl.querySelector('.card-title').textContent,
                    status: status
                });
            });
            localStorage.setItem(STORAGE_KEY, JSON.stringify(boardState));
        }

        /**
         * Loads the board state from localStorage and renders cards.
         */
        function loadBoardState() {
            const storedState = localStorage.getItem(STORAGE_KEY);
            if (storedState) {
                const cardsData = JSON.parse(storedState);
                cardsData.forEach(data => {
                    createCardElement(data.title, data.status);
                });
            }
        }

        // --- UI Rendering & Updates ---

        /**
         * Creates the DOM element for a card and appends it to the specified container.
         * @param {string} title - The text content of the card.
         * @param {string} status - The target column status ('todo', 'doing', 'done').
         */
        function createCardElement(title, status) {
            const card = document.createElement('div');
            card.className = 'card';
            card.setAttribute('draggable', 'true');
            card.dataset.status = status;

            // Card content structure
            card.innerHTML = `
                <span class="card-title">${title}</span>
                <button class="card-del" title="Delete card">&times;</button>
            `;

            // Append to the correct container
            columns[status].appendChild(card);

            // Reattach listeners for new elements
            setupCardListeners(card);
        }

        /**
         * Updates all visible count displays based on current DOM state.
         */
        function updateCounts() {
            const counts = { todo: 0, doing: 0, done: 0 };
            document.querySelectorAll('.column').forEach(col => {
                const status = col.dataset.status;
                counts[status] = col.querySelectorAll('.card').length;
            });

            countSpans.todo.textContent = counts.todo;
            countSpans.doing.textContent = counts.doing;
            countSpans.done.textContent = counts.done;
        }

        /**
         * Handles the creation of a new card from input text.
         */
        function handleAddCard() {
            const title = cardInput.value.trim();
            if (title) {
                // New cards always start in To Do
                createCardElement(title, 'todo');
                cardInput.value = ''; // Clear input
                saveBoardState();
                updateCounts();
            }
        }

        /**
         * Deletes a card element from the DOM and updates state/counts.
         * @param {HTMLElement} cardEl - The card element to delete.
         */
        function deleteCard(cardEl) {
            if (confirm("Are you sure you want to delete this card?")) {
                const status = cardEl.dataset.status;
                cardEl.remove();
                saveBoardState();
                updateCounts();
            }
        }

        // --- Event Handlers & Listeners Setup ---

        /**
         * Sets up listeners for a newly created card (delete button, drag start).
         * @param {HTMLElement} cardEl - The card element.
         */
        function setupCardListeners(cardEl) {
            const deleteButton = cardEl.querySelector('.card-del');

            // 1. Delete Listener
            if (deleteButton) {
                deleteButton.addEventListener('click', () => deleteCard(cardEl));
            }

            // 2. Drag Start Listener
            cardEl.addEventListener('dragstart', (e) => {
                draggedCardElement = cardEl;
                e.dataTransfer.setData('text/plain', cardEl.dataset.status); // Store source status
                setTimeout(() => {
                    cardEl.classList.add('dragging');
                }, 0);
            });

            // 3. Drag End Listener (Cleanup)
            cardEl.addEventListener('dragend', () => {
                cardEl.classList.remove('dragging');
                draggedCardElement = null;
            });
        }


        /**
         * Sets up drag and drop handlers on the column containers.
         */
        function setupDragAndDrop() {
            const containerElements = document.querySelectorAll('.card-container');

            containerElements.forEach(container => {
                // Drag Over: Allows dropping
                container.addEventListener('dragover', (e) => {
                    e.preventDefault(); // Necessary to allow drop
                    if (draggedCardElement && draggedCardElement.dataset.status !== container.dataset.status) {
                        container.classList.add('drag-over');
                    }
                });

                // Drag Leave: Removes visual feedback
                container.addEventListener('dragleave', () => {
                    container.classList.remove('drag-over');
                });

                // Drop: Handles the move logic
                container.addEventListener('drop', (e) => {
                    e.preventDefault();
                    container.classList.remove('drag-over');

                    if (draggedCardElement && draggedCardElement !== container.querySelector('.dragging')) {
                        const sourceStatus = draggedCardElement.dataset.status;
                        const targetStatus = container.dataset.status;

                        // 1. Move the card in the DOM
                        container.appendChild(draggedCardElement);

                        // 2. Update internal state tracking (optional, but good practice)
                        draggedCardElement.dataset.status = targetStatus;

                        // 3. Persist and update UI
                        saveBoardState();
                        updateCounts();
                    }
                });
            });
        }


        // --- Initialization ---

        function initialize() {
            // 1. Setup Event Listeners for Card Creation
            addCardButton.addEventListener('click', handleAddCard);
            cardInput.addEventListener('keypress', (e) => {
                if (e.key === 'Enter') {
                    handleAddCard();
                }
            });

            // 2. Load State and Render Cards
            loadBoardState();

            // 3. Setup Drag & Drop Functionality
            setupDragAndDrop();

            // 4. Initial Count Update (Crucial if state was loaded)
            updateCounts();
        }

        window.onload = initialize;

    </script>
</body>
</html>
